assignments.value:
={{
"You are Study Aura, an educational slide deck generator. Create exactly " + ($json.body.slideCount || 5) + " slide outlines for the topic: " + ($json.body.topic || "General Study") + ". Difficulty: " + ($json.body.difficulty || "easy") + ".\n\n" +
"Selected source context:\n" +
(
  Array.isArray($json.body.selectedSources) && $json.body.selectedSources.length > 0
    ? $json.body.selectedSources.map((source, index) => {
        return (index + 1) + ". " + (source.title || "Untitled Source") + " [" + (source.type || "source") + "]\n" +
          "Summary or content: " + (source.summary || source.value || "No summary provided.");
      }).join("\n\n")
    : "No selected sources were provided. Use the topic only."
) +
"\n\nReturn ONLY valid JSON. No markdown. No code fences.\n" +
"Required JSON format: {\"title\": string, \"description\": string, \"slides\": [{\"slideNumber\": number, \"title\": string, \"subtitle\": string, \"bullets\": string[], \"speakerNotes\": string, \"visualIdea\": string}]}.\n" +
"Rules:\n" +
"- Each slide must have 3 to 5 bullets.\n" +
"- Speaker notes should be concise and presentation-ready.\n" +
"- Visual ideas should be specific but simple to design.\n" +
"- Prioritize selected source context when available.\n" +
"- Do not include markdown, comments, or text outside JSON."
}}

parameters.jsCode:
const raw = $json.output ?? "";

const cleaned = String(raw)
  .replace(/```json/g, "")
  .replace(/```/g, "")
  .trim();

let deck;
let fallback = false;

try {
  deck = JSON.parse(cleaned);

  if (!deck.title || !Array.isArray(deck.slides)) {
    throw new Error("Invalid slides format");
  }
} catch (error) {
  fallback = true;
  deck = {
    title: "Study Aura Slide Deck",
    description: "A quick fallback slide outline for presenting a study topic.",
    slides: [
      {
        slideNumber: 1,
        title: "Topic Overview",
        subtitle: "Start with the main idea",
        bullets: ["Define the topic", "Explain why it matters", "Preview the key points"],
        speakerNotes: "Introduce the topic clearly and connect it to the learner's goal.",
        visualIdea: "Title slide with a simple topic icon and clean background"
      }
    ]
  };
}

const slides = Array.isArray(deck.slides)
  ? deck.slides.map((slide, index) => {
      const bullets = Array.isArray(slide.bullets)
        ? slide.bullets.map((bullet) => String(bullet)).slice(0, 5)
        : ["Review the key idea", "Explain one example", "Summarize the takeaway"];

      while (bullets.length < 3) {
        bullets.push("Add one supporting detail");
      }

      return {
        slideNumber: Number(slide.slideNumber || index + 1),
        title: String(slide.title || `Slide ${index + 1}`),
        subtitle: String(slide.subtitle || "Study Aura slide"),
        bullets,
        speakerNotes: String(slide.speakerNotes || "Explain this concept clearly."),
        visualIdea: String(slide.visualIdea || "Use a simple educational visual.")
      };
    })
  : [];

return [
  {
    json: {
      deck: {
        title: String(deck.title || "Study Aura Slide Deck"),
        description: String(deck.description || "Generated slide outline."),
        slides
      },
      fallback,
      provider: $json.provider || "gemini"
    }
  }
];

